/** @CustomParams
{
    "response_time": {
        "type": "int",
        "title": "Response Time (ms)",
        "required": false,
        "description": "Optional: Provide the response time from workflow logs or another node"
    }
}
*/

export default async function run({ execution_id, input, data }) {
    // 1. Fetch data from previous HTTP node (ID = 2)
    const html = data["{{2.`body`}}"] || "";
    const status = parseInt(data["{{2.`status`}}"], 10);

    // 2. Get response time from custom param or default to 0
    const responseTime = data.response_time || 0;

    // 3. Initialize report object
    let report = {
        is_healthy: true,
        alerts: [],
        metrics: {
            status: status,
            responseTime: responseTime + "ms",
            contentLength: html.length
        },
        seo: {},
        check_time: new Date().toLocaleString("pl-PL")
    };

    // --- CASE 1: Status Code Check ---
    if (status !== 200) {
        report.is_healthy = false;
        report.alerts.push(`KRYTYCZNY: Serwer zwrócił status ${status}`);
    }

    // --- CASE 2: Performance Check ---
    if (responseTime > 3000) {
        report.is_healthy = false;
        report.alerts.push(`OSTRZEŻENIE: Strona muli. Czas odpowiedzi: ${responseTime}ms`);
    }

    // --- CASE 3: Content Integrity ---
    const requiredKeywords = ["Legia", "Warszawa", "Sklep"];
    const missingKeywords = requiredKeywords.filter(word => !html.toLowerCase().includes(word.toLowerCase()));

    if (missingKeywords.length > 0) {
        report.is_healthy = false;
        report.alerts.push(`BŁĄD TREŚCI: Brak słów kluczowych: ${missingKeywords.join(", ")}`);
    }

    // --- CASE 4: Error Detection ---
    const errorPhrases = ["sql error", "database connection failed", "php fatal error"];
    const foundErrors = errorPhrases.filter(phrase => html.toLowerCase().includes(phrase));

    if (foundErrors.length > 0) {
        report.is_healthy = false;
        report.alerts.push(`WYKRYTO BŁĄD W KODZIE: ${foundErrors.join(", ")}`);
    }

    // --- CASE 5: SEO / Metadata ---
    const titleMatch = html.match(/<title>(.*?)<\/title>/);
    report.seo.title = titleMatch ? titleMatch[1] : "Brak tytułu!";

    // --- CASE 6: Email subject & body ---
    report.email_subject = report.is_healthy
        ? `✅ Legia.com OK (${status})`
        : `🚨 AWARIA Legia.com (${status})`;

    report.email_body = `
WYNIK MONITORINGU: ${report.is_healthy ? "✅ WSZYSTKO DZIAŁA" : "🚨 WYKRYTO PROBLEM"}
-------------------------------------------
Strona: https://legia.com
Status HTTP: ${report.metrics.status}
Czas odpowiedzi: ${report.metrics.responseTime}
Data sprawdzenia: ${report.check_time}

${report.is_healthy 
    ? "Wszystkie parametry (kod statusu i słowa kluczowe) są w normie." 
    : "UWAGA: Strona zwróciła błąd lub nie zawiera kluczowych słów. Sprawdź to ręcznie!"}

-------------------------------------------
Wiadomość wygenerowana automatycznie przez Latenode.
    `.trim();

    return report;
}

